mapper.insert:
INSERT INTO attendance_record (
    unit_id, user_id, attendance_date, check_in_time, check_out_time, check_in_address, check_out_address,
    check_in_latitude, check_in_longitude, check_in_distance_meters, check_in_result, check_in_fail_reason, valid_flag
)
VALUES (
    #{unitId}, #{userId}, #{attendanceDate}, #{checkInTime}, #{checkOutTime}, #{checkInAddress}, #{checkOutAddress},
    #{checkInLatitude}, #{checkInLongitude}, #{checkInDistanceMeters}, #{checkInResult}, #{checkInFailReason}, #{validFlag}
)

mapper.select:
SELECT id, unit_id, user_id, attendance_date, check_in_time, check_out_time,
       check_in_address, check_out_address, check_in_latitude, check_in_longitude,
       check_in_distance_meters, check_in_result, check_in_fail_reason, valid_flag, create_time
FROM attendance_record
WHERE user_id = #{userId}
  AND attendance_date = #{attendanceDate}

SELECT unit_name
FROM sys_org_unit
WHERE id = #{unitId}

mapper.update:
UPDATE attendance_record
SET valid_flag = #{validFlag}
WHERE id = #{id}

mapper.select:
SELECT COUNT(DISTINCT a.user_id)
FROM attendance_record a
INNER JOIN sys_user u ON u.id = a.user_id
WHERE 1 = 1
  AND u.is_deleted = FALSE

    AND a.attendance_date >= #{startDate}


    AND a.attendance_date <= #{endDate}


    AND a.valid_flag = #{validFlag}


    AND u.tree_path LIKE CONCAT(#{treePathPrefix}, '%')

SELECT a.id, a.unit_id, a.user_id, u.username, u.real_name, su.unit_name, a.attendance_date, a.check_in_time, a.check_out_time, a.check_in_address, a.check_out_address, a.check_in_latitude, a.check_in_longitude, a.check_in_distance_meters, a.check_in_result, a.check_in_fail_reason, a.valid_flag, a.create_time FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND a.check_in_result = #{request.checkInStatus}
AND a.user_id = #{request.userId}
AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
ORDER BY a.attendance_date DESC, a.check_in_time DESC NULLS LAST, a.id DESC LIMIT #{request.pageSize} OFFSET #{request.offset}

SELECT COUNT(1)
FROM attendance_record a
INNER JOIN sys_user u ON u.id = a.user_id
LEFT JOIN sys_org_unit su ON su.id = a.unit_id
WHERE u.is_deleted = FALSE

    AND (
        u.username LIKE CONCAT('%', #{request.keywords}, '%')
        OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%')
    )


    AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')


    AND a.attendance_date >= #{request.dateFrom}


    AND a.attendance_date <= #{request.dateTo}


    AND a.check_in_result = #{request.checkInStatus}


    AND a.user_id = #{request.userId}


    AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')


    AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')

SELECT a.check_in_result AS check_in_status, COUNT(1) AS count FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE
AND ( u.username LIKE CONCAT('%', #{request.keywords}, '%') OR u.real_name LIKE CONCAT('%', #{request.keywords}, '%') )
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND a.check_in_result = #{request.checkInStatus}
AND a.user_id = #{request.userId}
AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.check_in_result ORDER BY COUNT(1) DESC, a.check_in_result ASC

SELECT abnormal.user_id, abnormal.username, abnormal.real_name, abnormal.unit_name, totals.total_count, abnormal.abnormal_count, ROUND((abnormal.abnormal_count * 100.0) / NULLIF(totals.total_count, 0), 1) AS abnormal_rate FROM ( SELECT a.user_id, u.username, u.real_name, su.unit_name, COUNT(1) AS abnormal_count FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.user_id, u.username, u.real_name, su.unit_name ) abnormal INNER JOIN ( SELECT a.user_id, COUNT(1) AS total_count FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.user_id ) totals ON totals.user_id = abnormal.user_id ORDER BY abnormal.abnormal_count DESC, abnormal_rate DESC, abnormal.user_id ASC LIMIT 10

SELECT a.attendance_date, COUNT(1) AS total_count, SUM(CASE WHEN a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS') THEN 1 ELSE 0 END) AS abnormal_count, ROUND( (SUM(CASE WHEN a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS') THEN 1 ELSE 0 END) * 100.0) / NULLIF(COUNT(1), 0), 1 ) AS abnormal_rate FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.user_id = #{request.userId}
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.attendance_date ORDER BY a.attendance_date ASC

SELECT a.user_id,
       SUM(
           CASE
               WHEN a.attendance_date >= #{recentDateFrom}
                AND a.attendance_date <= #{recentDateTo}
                AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
               THEN 1 ELSE 0
           END
       ) AS recent7_day_abnormal_count,
       SUM(
           CASE
               WHEN a.attendance_date >= #{previousDateFrom}
                AND a.attendance_date <= #{previousDateTo}
                AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
               THEN 1 ELSE 0
           END
       ) AS previous7_day_abnormal_count
FROM attendance_record a
INNER JOIN sys_user u ON u.id = a.user_id
LEFT JOIN sys_org_unit su ON su.id = a.unit_id
WHERE u.is_deleted = FALSE
  AND a.attendance_date >= #{previousDateFrom}
  AND a.attendance_date <= #{recentDateTo}

    AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')


    AND a.user_id = #{request.userId}


    AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')

GROUP BY a.user_id

SELECT COALESCE(NULLIF(TRIM(a.check_in_fail_reason), ''), a.check_in_result) AS reason_key, COUNT(1) AS count FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.user_id = #{request.userId}
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY COALESCE(NULLIF(TRIM(a.check_in_fail_reason), ''), a.check_in_result) ORDER BY COUNT(1) DESC, reason_key ASC LIMIT 5

SELECT ranked.user_id, ranked.reason_key, ranked.count FROM ( SELECT a.user_id, COALESCE(NULLIF(TRIM(a.check_in_fail_reason), ''), a.check_in_result) AS reason_key, COUNT(1) AS count, ROW_NUMBER() OVER ( PARTITION BY a.user_id ORDER BY COUNT(1) DESC, COALESCE(NULLIF(TRIM(a.check_in_fail_reason), ''), a.check_in_result) ASC ) AS rn FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.user_id = #{request.userId}
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.user_id, COALESCE(NULLIF(TRIM(a.check_in_fail_reason), ''), a.check_in_result) ) ranked WHERE ranked.rn = 1 ORDER BY ranked.count DESC, ranked.user_id ASC

SELECT latest.user_id, latest.username, latest.real_name, latest.unit_name, counts.abnormal_count, latest.recent_abnormal_date, latest.recent_abnormal_type FROM ( SELECT a.user_id, u.username, u.real_name, su.unit_name, a.attendance_date AS recent_abnormal_date, a.check_in_result AS recent_abnormal_type FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.user_id = #{request.userId} AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
ORDER BY a.attendance_date DESC, a.check_in_time DESC NULLS LAST, a.id DESC LIMIT 1 ) latest INNER JOIN ( SELECT a.user_id, COUNT(1) AS abnormal_count FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.user_id = #{request.userId} AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
GROUP BY a.user_id ) counts ON counts.user_id = latest.user_id

SELECT a.check_in_address, a.check_in_time FROM attendance_record a INNER JOIN sys_user u ON u.id = a.user_id LEFT JOIN sys_org_unit su ON su.id = a.unit_id WHERE u.is_deleted = FALSE AND a.user_id = #{request.userId} AND a.check_in_result NOT IN ('CHECK_IN_SUCCESS', 'CHECK_OUT_SUCCESS')
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND a.attendance_date >= #{request.dateFrom}
AND a.attendance_date <= #{request.dateTo}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
ORDER BY a.attendance_date DESC, a.check_in_time DESC NULLS LAST, a.id DESC
